mapper.select:
SELECT COUNT(*) FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO

  W.USEYN = 1
  AND W.ORDDATE >= #{start_date}
  AND W.ORDDATE <= #{end_date}
  AND W.PLANTCD = #{plant_cd}
  AND W.SHIFT = #{shift}
  AND W.ORDSTATE = #{ord_state}
  AND (W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

SELECT W.WORKORDNO, W.ORDDATE, W.PARTNO, G.PARTNM, G.STANDARD, G.UNIT,
       W.ORDQTY, W.ORDTYPE, W.PROCESSCD, W.LINECD, W.SHIFT,
       W.ORDpriority, W.ORDSTATE, W.CLOSEYN, W.FIXEDYN,
       W.PAR_WORKORDNO, W.PLANTCD, W.REMARK
FROM TBL_PROD_WORKORDER W
LEFT JOIN TBL_COM_GOODS G ON W.PARTNO = G.PARTNO

  W.USEYN = 1
  AND W.ORDDATE >= #{start_date}
  AND W.ORDDATE <= #{end_date}
  AND W.PLANTCD = #{plant_cd}
  AND W.SHIFT = #{shift}
  AND W.ORDSTATE = #{ord_state}
  AND (W.PARTNO LIKE #{search} OR G.PARTNM LIKE #{search})

ORDER BY W.ORDDATE DESC, W.ORDpriority
OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

mapper.update:
UPDATE TBL_PROD_WORKORDER SET
  ORDQTY = #{ORDQTY}, PROCESSCD = #{PROCESSCD}, SHIFT = #{SHIFT},
  LINECD = #{LINECD}, ORDTYPE = #{ORDTYPE}, ORDpriority = #{ORDpriority},
  ORDSTATE = #{ORDSTATE}, EDITUSERID = #{EDITUSERID}, EDITDTM = GETDATE(),
  REMARK = #{REMARK}
WHERE WORKORDNO = #{WORKORDNO}
